#include <linux/udp.h>

int main() {
    int sock = socket(AF_INET, SOCK_DGRAM, 0);
    if (sock < 0) {
        perror("socket");
        return 1;
    }

    int optval = 1;
    // 启用UDP_GRO
    if (setsockopt(sock, IPPROTO_UDP, UDP_GRO, &optval, sizeof(optval)) < 0) {
        perror("setsockopt");
        close(sock);
        return 1;
