// 模拟漏洞触发
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void vulnerable(char *buf, size_t len) {
    char *heap_buf = malloc(64);
    // 假设这里存在溢出：memcpy(heap_buf, buf, len);  // len > 64
    memcpy(heap_buf, buf, len);  // 溢出
    free(heap_buf);
}

int main() {
    char payload[128];
    memset(payload, 'A', 128);
    // 在偏移64处放置一个函数指针，例如覆盖__free_hook
    // 实际需要计算偏移
    vulnerable(payload, 128);
    return 0;
